// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

/**
 * Unit spec for factorized-order selection: the sink reorder ({@link MultiJoinPlan#derivedFactorizedPlan}) only pays
 * off through the branches the factorized tail actually claims. When the tail declines entirely, execution must fall
 * back to the compiler order — running the sunk order without a tail only delays the pruning the compiler order
 * provides. When the tail claims just part of the sunk suffix, the unclaimed patterns must return to their compiler
 * positions instead of lingering at the end of the nested-loop prefix.
 */
public class LmdbNativeFactorizedOrderSelectionTest {

	private static final int ROOT = 0;
	private static final int GROUP = 1;
	private static final int COUNTED = 2;
	private static final int EXTRA = 3;

	private static PatternPlan pattern(Term s, Term o, double estimate) {
		return new PatternPlan(s, Term.constant(7), o, Term.unbound(), ContextConstraint.UNRESTRICTED, false, estimate);
	}

	@Test
	public void declinedTailFallsBackToCompilerOrder() {
		PatternPlan driver = pattern(Term.slot(ROOT), Term.constant(11), 10);
		PatternPlan summed = pattern(Term.slot(ROOT), Term.slot(COUNTED), 100);
		PatternPlan stationary = pattern(Term.slot(ROOT), Term.constant(999), 50);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { driver, summed, stationary }, new MaskedFilter[0]);

		// precondition: the sink displaces the unconsumed pattern to the trailing suffix
		assertThat(plan.derivedFactorizedPlan(0L).order).containsExactly(driver, stationary, summed);

		// SUM DISTINCT keeps the tail on the enumerating path: the probe declines outright
		AggregateSpec[] specs = { AggregateSpec.slot("s", COUNTED, true, AggKind.SUM) };
		FactorizedTail.Selection selection = FactorizedTail.select(plan, 0L, new int[0], specs,
				LmdbNativeAttemptMetrics.direct());

		assertThat(selection.tail).isNull();
		assertThat(selection.derived.order)
				.as("a declined tail must run the compiler order, not the sunk order")
				.containsExactly(driver, summed, stationary);
	}

	@Test
	public void partiallyClaimedSinkRestoresUnclaimedPatternPosition() {
		PatternPlan groupProducer = pattern(Term.slot(ROOT), Term.slot(GROUP), 100);
		PatternPlan driver = pattern(Term.slot(ROOT), Term.constant(11), 10);
		PatternPlan counted = pattern(Term.slot(ROOT), Term.slot(COUNTED), 200);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { groupProducer, driver, counted },
				new MaskedFilter[0]);

		// precondition: both unconsumed patterns sink behind the driver
		assertThat(plan.derivedFactorizedPlan(0L).order).containsExactly(driver, groupProducer, counted);

		// the group key comes from groupProducer, so the tail can never claim it as a branch
		AggregateSpec[] specs = { AggregateSpec.slot("c", COUNTED, false, AggKind.COUNT) };
		FactorizedTail.Selection selection = FactorizedTail.select(plan, 0L, new int[] { GROUP }, specs,
				LmdbNativeAttemptMetrics.direct());

		assertThat(selection.tail).isNotNull();
		assertThat(selection.derived.order)
				.as("the unclaimable group producer must keep its compiler position")
				.containsExactly(groupProducer, driver, counted);
	}

	@Test
	public void fullyClaimedSinkKeepsSunkOrder() {
		PatternPlan extraProducer = pattern(Term.slot(ROOT), Term.slot(EXTRA), 100);
		PatternPlan driver = pattern(Term.slot(ROOT), Term.constant(11), 10);
		PatternPlan counted = pattern(Term.slot(ROOT), Term.slot(COUNTED), 200);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { extraProducer, driver, counted },
				new MaskedFilter[0]);

		assertThat(plan.derivedFactorizedPlan(0L).order).containsExactly(driver, extraProducer, counted);

		AggregateSpec[] specs = { AggregateSpec.star("c") };
		FactorizedTail.Selection selection = FactorizedTail.select(plan, 0L, new int[0], specs,
				LmdbNativeAttemptMetrics.direct());

		assertThat(selection.tail).isNotNull();
		assertThat(selection.tail.branchCount()).isEqualTo(2);
		assertThat(selection.derived.order)
				.as("a fully claimed sink keeps the factorized order")
				.containsExactly(driver, extraProducer, counted);
	}

	@Test
	public void orderedFlatPrefixRequirementRestoresUnclaimedPatternPosition() {
		PatternPlan groupProducer = pattern(Term.slot(ROOT), Term.slot(GROUP), 100);
		PatternPlan driver = pattern(Term.slot(ROOT), Term.constant(11), 10);
		PatternPlan counted = pattern(Term.slot(ROOT), Term.slot(COUNTED), 200);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { groupProducer, driver, counted },
				new MaskedFilter[0]);

		assertThat(plan.derivedFactorizedPlan(0L).order).containsExactly(driver, groupProducer, counted);

		// an ORDER BY key produced by the sunk pattern forces it back into the flat prefix
		MultiJoinPlan.OrderedPlan selected = LmdbNativeFactorizedRows.selectFactorizedOrder(plan, 0L, 1L << GROUP, 0);

		assertThat(selected.order)
				.as("a branch forced into the flat prefix must keep its compiler position")
				.containsExactly(groupProducer, driver, counted);
	}

	@Test
	public void unrestrictedFlatSplitKeepsSunkOrder() {
		PatternPlan groupProducer = pattern(Term.slot(ROOT), Term.slot(GROUP), 100);
		PatternPlan driver = pattern(Term.slot(ROOT), Term.constant(11), 10);
		PatternPlan counted = pattern(Term.slot(ROOT), Term.slot(COUNTED), 200);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { groupProducer, driver, counted },
				new MaskedFilter[0]);

		MultiJoinPlan.OrderedPlan selected = LmdbNativeFactorizedRows.selectFactorizedOrder(plan, 0L, 0L, 1);

		assertThat(selected.order).containsExactly(driver, groupProducer, counted);
	}
}
